import React from 'react';
import logo from './logo.svg';
import './App.css';

function App() {

document.addEventListener('DOMContentLoaded', function() {
  const dropArea = document.getElementById('drop-area');
  const fileInput = document.getElementById('file-input');
  const uploadBtn = document.getElementById('upload-btn');
  const fileList = document.getElementById('file-list');

  // Chat widget functionality
  const chatButton = document.getElementById('chat-button');
  const chatContainer = document.getElementById('chat-container');
  const chatClose = document.getElementById('chat-close');
  const chatInput = document.querySelector('.chat-input');
  const chatSendBtn = document.querySelector('.chat-send-btn');

  chatButton.addEventListener('click', () => {
      chatContainer.classList.add('active');
  });

  chatClose.addEventListener('click', () => {
      chatContainer.classList.remove('active');
  });

  function sendMessage() {
      const message = chatInput.value.trim();
      if (message) {
          const chatMessages = document.querySelector('.chat-messages');

          // Add user message
          const userMessage = document.createElement('div');
          userMessage.className = 'message message-user';
          userMessage.textContent = message;
          chatMessages.appendChild(userMessage);

          // Clear input
          chatInput.value = '';

          // Auto scroll to bottom
          chatMessages.scrollTop = chatMessages.scrollHeight;

          // Simulate bot response
          setTimeout(() => {
              const botMessage = document.createElement('div');
              botMessage.className = 'message message-bot';
              botMessage.textContent = 'blah blah.';
              chatMessages.appendChild(botMessage);

              // Auto scroll to bottom
              chatMessages.scrollTop = chatMessages.scrollHeight;
          }, 1000);
      }
  }

  chatSendBtn.addEventListener('click', sendMessage);

  chatInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') {
          sendMessage();
      }
  });

  let files = [];

  // Open file browser when clicking on drop area
  dropArea.addEventListener('click', () => {
      fileInput.click();
  });

  // Handle file selection from file browser
  fileInput.addEventListener('change', (e) => {
      handleFiles(e.target.files);
  });

  // Prevent default drag behaviors
  ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
      dropArea.addEventListener(eventName, preventDefaults, false);
  });

  function preventDefaults(e) {
      e.preventDefault();
      e.stopPropagation();
  }

  // Highlight drop area when file is dragged over it
  ['dragenter', 'dragover'].forEach(eventName => {
      dropArea.addEventListener(eventName, highlight, false);
  });

  ['dragleave', 'drop'].forEach(eventName => {
      dropArea.addEventListener(eventName, unhighlight, false);
  });

  function highlight() {
      dropArea.style.borderColor = 'var(--primary)';
      dropArea.style.backgroundColor = 'rgba(0, 194, 203, 0.1)';
  }

  function unhighlight() {
      dropArea.style.borderColor = '#444';
      dropArea.style.backgroundColor = 'transparent';
  }

  // Handle dropped files
  dropArea.addEventListener('drop', (e) => {
      const dt = e.dataTransfer;
      const newFiles = dt.files;
      handleFiles(newFiles);
  });

  function handleFiles(newFiles) {
      const validFiles = Array.from(newFiles).filter(file => {
          // Check if file is a PDF
          return file.type === 'application/pdf';
      });

      if (validFiles.length === 0) {
          alert('Please upload PDF files only.');
          return;
      }

      // Add valid files to our files array
      files = [...files, ...validFiles];

      // Enable upload button if we have files
      if (files.length > 0) {
          uploadBtn.disabled = false;
      }

      // Update UI with file list
      updateFileList();
  }

  function updateFileList() {
      // Clear the file list
      fileList.innerHTML = '';

      // Add each file to the list
      files.forEach((file, index) => {
          const fileItem = document.createElement('div');
          fileItem.className = 'file-item';

          const fileInfo = document.createElement('div');

          const fileName = document.createElement('div');
          fileName.className = 'file-name';
          fileName.textContent = file.name;

          const fileSize = document.createElement('div');
          fileSize.className = 'file-size';
          fileSize.textContent = formatFileSize(file.size);

          fileInfo.appendChild(fileName);
          fileInfo.appendChild(fileSize);

          const status = document.createElement('div');
          status.className = 'status pending';
          status.textContent = 'Pending';

          const removeBtn = document.createElement('button');
          removeBtn.textContent = 'Remove';
          removeBtn.className = 'btn';
          removeBtn.style.backgroundColor = '#e63946';
          removeBtn.style.marginLeft = '10px';

          // Add event listener to remove button
          removeBtn.addEventListener('click', () => {
              files.splice(index, 1);
              updateFileList();
              if (files.length === 0) {
                  uploadBtn.disabled = true;
              }
          });

          const actions = document.createElement('div');
          actions.style.display = 'flex';
          actions.style.alignItems = 'center';
          actions.appendChild(status);
          actions.appendChild(removeBtn);

          fileItem.appendChild(fileInfo);
          fileItem.appendChild(actions);

          fileList.appendChild(fileItem);
      });
  }

  function formatFileSize(bytes) {
      if (bytes === 0) return '0 Bytes';

      const k = 1024;
      const sizes = ['Bytes', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));

      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  }

  // Handle file upload
  uploadBtn.addEventListener('click', () => {
      const fileItems = fileList.querySelectorAll('.file-item');

      fileItems.forEach((fileItem, index) => {
          const statusElement = fileItem.querySelector('.status');
          statusElement.textContent = 'Uploading...';

          // Simulate upload delay
          setTimeout(() => {
              statusElement.textContent = 'Success';
              statusElement.className = 'status success';
          }, 1500 + (index * 500)); // Stagger the uploads for a more realistic feel
      });

      // Add a notification in the chat when files are uploaded
      setTimeout(() => {
          if (!chatContainer.classList.contains('active')) {
              chatContainer.classList.add('active');
          }

          const chatMessages = document.querySelector('.chat-messages');
          const message = document.createElement('div');
          message.className = 'message message-bot';
          message.textContent = 'I see you\'ve uploaded some files. The analysis will be completed shortly.';
          chatMessages.appendChild(message);
          chatMessages.scrollTop = chatMessages.scrollHeight;
      }, 2000);
  });
});
  return (
    <div>
      <head>
        <meta charSet="UTF-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1.0" />
        <title>XR-AI - X-ray Fracture Detection</title>
      </head>
      <body>
        <header>
          <div className="container">
            <h1 className="logo">XR-AI</h1>
            <p className="tagline">Advanced X-ray Fracture Detection</p>
          </div>
        </header>

        <main className="container">
          <section className="upload-section">
            <div className="upload-container">
              <h2>Upload X-ray Images</h2>
              <p className="upload-description">
                Upload your X-ray images in PDF format for AI-powered fracture detection and analysis.
              </p>

              <div className="upload-area" id="drop-area">
                <div className="upload-text">Drag and drop your X-ray PDFs here</div>
                <div className="file-info">or click to browse (Max size: 10MB)</div>
                <input type="file" id="file-input" accept=".pdf" multiple />
              </div>

              <div className="text-center">
                <button className="btn" id="upload-btn" disabled>
                  Upload Files
                </button>
              </div>

              <div className="file-list" id="file-list">
                {/* File items will be added here via JavaScript */}
              </div>
            </div>
          </section>
        </main>

        {/* Chat Widget */}
        <div className="chat-widget">
          <div className="chat-button" id="chat-button">Chat</div>

          <div className="chat-container" id="chat-container">
            <div className="chat-header">
              <div className="chat-title-container">
                <div className="chat-online-indicator"></div>
                <h3 className="chat-title">XR-AI Assistant</h3>
              </div>
              <div className="chat-close" id="chat-close">×</div>
            </div>

            <div className="chat-messages">
              <div className="message message-bot">Hello!</div>
            </div>

            <div className="chat-input-container">
              <input type="text" className="chat-input" placeholder="Type your message here..." />
              <button className="chat-send-btn">→</button>
            </div>
          </div>
        </div>

        <footer>
          <div className="container">
            <div className="footer-content">
              <div className="footer-logo">XR-AI</div>
              <div>© 2025 XR-AI Medical Imaging. All rights reserved.</div>
            </div>
          </div>
        </footer>
      </body>
    </div>
  );
}

export default App;
